import{_ as e,o as a,c as o,a2 as l}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"医门法律·秋燥论","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/10-喻嘉言（秋燥论）.md","filePath":"tcm-data/04-明清/10-喻嘉言（秋燥论）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/04-明清/10-喻嘉言（秋燥论）.md"};function n(s,t,i,d,h,g){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="医门法律·秋燥论" tabindex="-1">医门法律·秋燥论 <a class="header-anchor" href="#医门法律·秋燥论" aria-label="Permalink to &quot;医门法律·秋燥论&quot;">​</a></h1><blockquote><p>喻嘉言（1585-1664年），江西新建人 清初三大医家之一，&quot;秋燥论&quot;的创导者 代表作：《医门法律》《尚论篇》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名昌，字嘉言</li><li><strong>生平</strong>：明末清初，明亡后剃度为僧，后还俗行医</li><li><strong>经历</strong>：与张璐、吴谦并称清初三大医家</li><li><strong>学术地位</strong>：<strong>&quot;秋燥论&quot;的创导者</strong>，补充了《内经》&quot;秋伤于湿&quot;之不足</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-秋燥论" tabindex="-1">1. 秋燥论 <a class="header-anchor" href="#_1-秋燥论" aria-label="Permalink to &quot;1. 秋燥论&quot;">​</a></h3><p>喻嘉言指出《内经》&quot;秋伤于湿&quot;是错误的——秋主燥，当为&quot;秋伤于燥&quot;：</p><blockquote><p><strong>「春伤于风、夏伤于暑、长夏伤于湿、秋伤于燥、冬伤于寒。」</strong></p></blockquote><h3 id="_2-燥证的病机" tabindex="-1">2. 燥证的病机 <a class="header-anchor" href="#_2-燥证的病机" aria-label="Permalink to &quot;2. 燥证的病机&quot;">​</a></h3><blockquote><p><strong>「燥者，干也。诸涩枯涸，干劲皴揭，皆属于燥。」</strong></p></blockquote><p><strong>普明</strong>：口干+皮肤干+足跟裂→燥证 <strong>普光</strong>：脚后跟开裂+皮肤干燥蜕皮→燥证</p><h3 id="_3-清燥救肺" tabindex="-1">3. 清燥救肺 <a class="header-anchor" href="#_3-清燥救肺" aria-label="Permalink to &quot;3. 清燥救肺&quot;">​</a></h3><p>喻嘉言创立了<strong>清燥救肺法</strong>——&quot;清燥火、救肺金&quot;。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>清燥救肺汤</strong></td><td style="text-align:left;">桑叶、石膏、人参、甘草、麻仁、阿胶、麦冬、杏仁、枇杷叶</td><td style="text-align:left;">秋燥咳嗽、干咳无痰</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「春伤于风、夏伤于暑、秋伤于燥、冬伤于寒。」</strong></p></blockquote><blockquote><p><strong>「燥者，干也。诸涩枯涸，干劲皴揭，皆属于燥。」</strong></p></blockquote><blockquote><p><strong>「治燥不同治火。治火可用苦寒，治燥必用甘寒。」</strong></p></blockquote><blockquote><p><strong>「清燥救肺，甘寒为上。」</strong></p></blockquote><hr><h2 id="五、对普光-普明的参考" tabindex="-1">五、对普光/普明的参考 <a class="header-anchor" href="#五、对普光-普明的参考" aria-label="Permalink to &quot;五、对普光/普明的参考&quot;">​</a></h2><p><strong>治燥与治火不同</strong>——喻嘉言这句话很重要：</p><table tabindex="0"><thead><tr><th style="text-align:left;">证</th><th style="text-align:left;">治法</th><th style="text-align:left;">举例</th></tr></thead><tbody><tr><td style="text-align:left;">火证</td><td style="text-align:left;">苦寒</td><td style="text-align:left;">黄连、黄芩</td></tr><tr><td style="text-align:left;">燥证</td><td style="text-align:left;">甘寒</td><td style="text-align:left;"><strong>麦冬、百合、阿胶</strong></td></tr></tbody></table><p>普明的&quot;加减黄芽地魄汤&quot;中已有<strong>麦冬12g</strong> → 正是甘寒润燥。</p><p>普光的脚后跟开裂 → 可在冬季加麦冬或当归。</p><hr><p><em>本条目为精简框架版。</em></p>',32)])])}const q=e(r,[["render",n]]);export{c as __pageData,q as default};
